// Build source slug -> ID map from Supabase, then define feeds
const sourcesData = $('Fetch Source IDs').first().json;
const sourceRows = Array.isArray(sourcesData) ? sourcesData : (sourcesData.body || []);
const sourceMap = {};
for (const s of sourceRows) { sourceMap[s.slug] = s.id; }

const feeds = [
  { source_slug: 'scmp', name: 'South China Morning Post', url: 'https://www.scmp.com/rss/91/feed' },
  { source_slug: 'bbc', name: 'BBC World News', url: 'https://feeds.bbci.co.uk/news/world/rss.xml' },
  { source_slug: 'nyt', name: 'New York Times World', url: 'https://rss.nytimes.com/services/xml/rss/nyt/World.xml' },
  { source_slug: 'aljazeera', name: 'Al Jazeera', url: 'https://www.aljazeera.com/xml/rss/all.xml' },
  { source_slug: 'ft', name: 'Financial Times', url: 'https://www.ft.com/world?format=rss' },
  { source_slug: 'berlingske', name: 'Berlingske', url: 'https://www.berlingske.dk/content/rss' },
  { source_slug: 'borsen', name: 'Borsen', url: 'https://borsen.dk/rss/investor' },
  { source_slug: 'economist-finance', name: 'The Economist (Finance)', url: 'https://www.economist.com/finance-and-economics/rss.xml' },
  { source_slug: 'economist-europe', name: 'The Economist (Europe)', url: 'https://www.economist.com/europe/rss.xml' },
  { source_slug: 'economist-asia', name: 'The Economist (Asia)', url: 'https://www.economist.com/asia/rss.xml' },
  { source_slug: 'economist-business', name: 'The Economist (Business)', url: 'https://www.economist.com/business/rss.xml' },
  { source_slug: 'eurostat', name: 'Eurostat', url: 'https://ec.europa.eu/eurostat/api/dissemination/catalogue/rss/en/statistics-update.rss' }
];

return feeds.map(f => ({
  json: { ...f, source_id: sourceMap[f.source_slug] || sourceMap[f.source_slug.split('-')[0]] || '' }
}));

// Process RSS items into article records
const items = $input.all();
const sourceInfo = $('Feed List').first().json;

const articles = items
  .filter(item => item.json.title && item.json.link)
  .slice(0, 10)
  .map(item => {
    const content = (item.json['content:encoded'] || item.json.description || item.json.title)
      .replace(/<[^>]*>/g, '').trim();

    // FNV-1a hash for Pinecone dedup ID
    const urlBytes = new TextEncoder().encode(item.json.link);
    let h = 0x811c9dc5;
    for (const b of urlBytes) { h ^= b; h = Math.imul(h, 0x01000193); }
    const urlHash = Math.abs(h).toString(16).padStart(8, '0');

    // Deterministic UUID from URL hash (for Supabase dedup)
    const pad = (s, n) => s.padStart(n, '0').slice(0, n);
    const h1 = Math.abs(h).toString(16);
    const h2 = Math.abs(h >>> 4).toString(16);
    const h3 = Math.abs(h >>> 8).toString(16);
    const h4 = Math.abs(h >>> 12).toString(16);
    const h5 = Math.abs(h >>> 16).toString(16);
    const articleId = `${pad(h1,8)}-${pad(h2,4)}-4${pad(h3,3)}-8${pad(h4,3)}-${pad(h5,12)}`;

    return {
      json: {
        pinecone_id: `${sourceInfo.source_slug}-${urlHash}`,
        article_id: articleId,
        title: item.json.title.trim(),
        url: item.json.link.trim(),
        content: content.substring(0, 2000),
        excerpt: content.substring(0, 300),
        source: sourceInfo.name,
        source_slug: sourceInfo.source_slug,
        source_id: sourceInfo.source_id,
        published_at: item.json.pubDate || new Date().toISOString()
      }
    };
  });

return articles.length > 0 ? articles : [{ json: { _skip: true } }];
